using UnityEngine;

public class AnimatorExample : MonoBehaviour
{
    private Animator animator;

    // Animation parameters
    public string speedParameter = "Speed";
    public string isGroundedParameter = "IsGrounded";
    public string jumpParameter = "Jump";
    public string attackParameter = "Attack";
    public string deathParameter = "Death";

    void Start()
    {
        // Get the Animator component
        animator = GetComponent<Animator>();

        if (animator == null)
        {
            Debug.LogError("Animator component is missing!");
        }
    }

    void Update()
    {
        if (animator == null) return;

        // Example: Set Speed based on horizontal input
        float horizontal = Input.GetAxis("Horizontal");
        float speed = Mathf.Abs(horizontal);
        animator.SetFloat(speedParameter, speed);

        // Example: Set IsGrounded
        // animator.SetBool(isGroundedParameter, isGrounded);

        // Example: Trigger Jump
        if (Input.GetButtonDown("Jump"))
        {
            animator.SetTrigger(jumpParameter);
        }

        // Example: Trigger Attack
        if (Input.GetButtonDown("Fire1"))
        {
            animator.SetTrigger(attackParameter);
        }

        // Example: Trigger Death
        if (Input.GetKeyDown(KeyCode.K))
        {
            animator.SetTrigger(deathParameter);
        }
    }

    // Example: Animation events
    // Called by animation events
    public void OnAttackEvent()
    {
        Debug.Log("Attack animation event triggered!");
        // Deal damage, spawn particles, etc.
    }

    public void OnFootstepEvent()
    {
        Debug.Log("Footstep!");
        // Play footstep sound
    }

    public void OnDeathEvent()
    {
        Debug.Log("Death animation complete!");
        // Disable player, game over, etc.
    }

    // Example: Set animation parameter
    public void SetBool(string parameter, bool value)
    {
        if (animator != null)
        {
            animator.SetBool(parameter, value);
        }
    }

    public void SetFloat(string parameter, float value)
    {
        if (animator != null)
        {
            animator.SetFloat(parameter, value);
        }
    }

    public void SetTrigger(string parameter)
    {
        if (animator != null)
        {
            animator.SetTrigger(parameter);
        }
    }

    public void SetInteger(string parameter, int value)
    {
        if (animator != null)
        {
            animator.SetInteger(parameter, value);
        }
    }
}

